appsmith.onReady(() => {
  appsmith.onModelChange(model => {
    const rawData = model.cookies || {};
    const summary = rawData.components?.summary || {};
    const byProvider = summary.by_provider || {};
    const byType = summary.by_type || {};

    // --- 1. Taxonomy Separation (Vendors vs Serialization) ---
    const serializationTypes = ['Pickle', 'Joblib', 'H5', 'PT', 'Safetensors'];
    let maxArtifactCount = 0;
    let dominantArtifact = "None";
    let activeVendorCount = 0;
    const providers = Object.entries(byProvider);
    const processedEntities = providers.map(([name, count]) => {
      const isSerialization = serializationTypes.includes(name);
      let category = isSerialization ? 'Serialization Format' : 'AI Vendor / Tooling';
      if (name === 'Various') category = 'Mixed Ecosystem';

      // Find dominant artifact
      if (isSerialization && count > maxArtifactCount) {
        maxArtifactCount = count;
        dominantArtifact = name;
      }

      // Count actual vendors
      if (!isSerialization && name !== 'Various') {
        activeVendorCount++;
      }
      return {
        name,
        count,
        category,
        isSerialization
      };
    });

    // --- 2. Calculate AI Boundary Exposure Index (BALANCED) ---
    const boundaryCrossings = rawData.cross_file?.ai_boundaries || 0;
    const undeclaredComponents = (byType.llm_framework?.count || 0) + (byType.agent?.count || 0);
    const eligibilityViolations = rawData.crossings?.prohibited_count || 0;

    // Balanced weights to prevent the score from maxing out instantly
    const boundaryPenalty = boundaryCrossings * 10;
    const vendorPenalty = activeVendorCount * 5;
    const frameworkPenalty = undeclaredComponents * 2;

    // Base penalty of 10 for having serialization risks, plus 1 point per file
    const serializationPenalty = maxArtifactCount > 0 ? 10 + maxArtifactCount * 1 : 0;
    const eligibilityPenalty = eligibilityViolations * 20;
    const rawScore = boundaryPenalty + vendorPenalty + frameworkPenalty + serializationPenalty + eligibilityPenalty;
    const indexScore = Math.min(100, rawScore);

    // Update UI Cards & Explanation
    document.getElementById('dominant-artifact').innerText = dominantArtifact;
    document.getElementById('active-vendors').innerText = activeVendorCount;
    document.getElementById('exposure-index').innerText = `${indexScore}/100`;
    document.getElementById('index-explanation').innerText = `Score factors: ${boundaryPenalty} pts (Boundaries), ${vendorPenalty} pts (Vendors), ${frameworkPenalty} pts (Frameworks), ${serializationPenalty} pts (Serialization), ${eligibilityPenalty} pts (Violations).`;

    // --- 3. Populate Taxonomy Table with Integrity Flags ---
    const tbody = document.getElementById('taxonomy-table-body');
    tbody.innerHTML = '';
    if (processedEntities.length === 0) {
      tbody.innerHTML = '<tr><td colspan="5" style="text-align: center;">No providers detected.</td></tr>';
      return;
    }

    // Sort: Critical serialization formats first, then vendors
    processedEntities.sort((a, b) => b.isSerialization - a.isSerialization || b.count - a.count).forEach(entity => {
      const tr = document.createElement('tr');
      const tdName = document.createElement('td');
      tdName.innerHTML = `<strong>${entity.name}</strong>`;
      const tdCat = document.createElement('td');
      tdCat.textContent = entity.category;
      const tdCount = document.createElement('td');
      tdCount.textContent = entity.count;

      // Integrity & Signature Flags
      const tdIntegrity = document.createElement('td');
      const integrityBadge = document.createElement('span');
      if (entity.isSerialization) {
        integrityBadge.className = 'badge badge-critical';
        integrityBadge.textContent = 'Unsigned / No Verification';
      } else {
        integrityBadge.className = 'badge badge-safe';
        integrityBadge.textContent = 'Provider API / Verified';
      }
      tdIntegrity.appendChild(integrityBadge);

      // Risk Weight
      const tdWeight = document.createElement('td');
      const weightBadge = document.createElement('span');
      if (entity.isSerialization || entity.name === 'Google') {
        weightBadge.className = 'badge badge-critical';
        weightBadge.textContent = 'High Exposure';
      } else {
        weightBadge.className = 'badge badge-neutral';
        weightBadge.textContent = 'Standard';
      }
      tdWeight.appendChild(weightBadge);
      tr.appendChild(tdName);
      tr.appendChild(tdCat);
      tr.appendChild(tdCount);
      tr.appendChild(tdIntegrity);
      tr.appendChild(tdWeight);
      tbody.appendChild(tr);
    });
  });
});

